fn panic_payload(p: &Box<dyn std::any::Any + Send>) -> String {
    if let Some(s) = p.downcast_ref::<String>() {
        s.clone()
    } else if let Some(s) = p.downcast_ref::<&'static str>() {
        s.to_string()
    } else {
        "<non-string panic payload>".to_string()
    }
}

fn dispatch(station: &Station, socket: &UdpSocket, peer: std::net::SocketAddr, frame: FlowFrame) {
    match frame.stream_id {
        ROUTE_HEALTH => handle_health(station, socket, &peer, frame.sequence),
        ROUTE_EMBED => handle_embed(station, frame, socket, &peer),
        ROUTE_FORWARD => handle_forward(station, frame, socket, &peer),
        ROUTE_LM_HEAD => handle_lm_head(station, frame, socket, &peer),
        ROUTE_COBORDISM_EMBED => handle_cobordism_embed(station, frame, socket, &peer),
        ROUTE_COBORDISM_LM_HEAD => handle_cobordism_lm_head(station, frame, socket, &peer),
        STREAM_LIQUID_SHARD_CMD => handle_liquid_shard(station, frame, socket, &peer),
        other => send_error(
            socket,
            &peer,
            other,
            frame.sequence,
            404,
            &format!("no route for stream_id=0x{:04x}", other),
        ),
    }
}

/// Inbound reassembly bucket — keyed by (peer, stream_id, sequence) on
/// the dispatcher side. Multi-datagram REQUESTS arrive here when the
/// client must split a large residual to fit under macOS's 9216 B
/// `net.inet.udp.maxdgram` ceiling.
struct InboundBucket {
    total: u16,
    chunks: std::collections::HashMap<u16, Vec<u8>>,
    stream_id: u16,
    base_flags: u8,
    last_seen: std::time::Instant,
}

type InboundTable = std::collections::HashMap<(std::net::SocketAddr, u16, u32), InboundBucket>;

fn dispatcher_loop(station: Arc<Station>, socket: Arc<UdpSocket>) -> ! {
    let mut buf = vec![0u8; RECV_BUF_SIZE];
    let mut inbound: InboundTable = std::collections::HashMap::new();
    let inbound_ttl = std::time::Duration::from_secs(60);
    loop {
        let (n, peer) = match socket.recv_from(&mut buf) {
            Ok(v) => v,
            Err(e) => {
                eprintln!("[fat-station-flow-udp] recv error: {}", e);
                continue;
            }
        };

        // GC stale buckets opportunistically.
        let now = std::time::Instant::now();
        inbound.retain(|_, b| now.duration_since(b.last_seen) < inbound_ttl);

        let frame = match decode_flow_frame(&buf[..n]) {
            Ok(f) => f,
            Err(e) => {
                send_error(&socket, &peer, 0, 0, 400, &e);
                continue;
            }
        };

        // Single-datagram request — dispatch directly.
        if (frame.flags & FLAG_CHUNK) == 0 {
            let st = Arc::clone(&station);
            let sk = Arc::clone(&socket);
            std::thread::spawn(move || {
                dispatch(&st, &sk, peer, frame);
            });
            continue;
        }

        // Chunked request: peel the [idx | total] prefix and accumulate.
        let p = frame.payload;
        if p.len() < 4 {
            send_error(
                &socket,
                &peer,
                frame.stream_id,
                frame.sequence,
                400,
                "chunk frame missing 4-byte idx/total prefix",
            );
            continue;
        }
        let idx = u16::from_be_bytes([p[0], p[1]]);
        let total = u16::from_be_bytes([p[2], p[3]]);
        if total == 0 || idx >= total {
            send_error(
                &socket,
                &peer,
                frame.stream_id,
                frame.sequence,
                400,
                &format!("chunk idx={} total={} (invalid)", idx, total),
            );
            continue;
        }
        let key = (peer, frame.stream_id, frame.sequence);
        let bucket = inbound.entry(key).or_insert(InboundBucket {
            total,
            chunks: std::collections::HashMap::new(),
            stream_id: frame.stream_id,
            base_flags: frame.flags & !(FLAG_CHUNK | FLAG_FIN),
            last_seen: now,
        });
        if bucket.total != total {
            send_error(
                &socket,
                &peer,
                frame.stream_id,
                frame.sequence,
                400,
                &format!(
                    "chunk total mismatch: bucket={} frame={}",
                    bucket.total, total
                ),
            );
            inbound.remove(&key);
            continue;
        }
        bucket.last_seen = now;
        bucket.chunks.insert(idx, p[4..].to_vec());
        if bucket.chunks.len() < bucket.total as usize {
            continue;
        }

        // All chunks present — reassemble in order and dispatch.
        let bucket = inbound.remove(&key).unwrap();
        let mut payload = Vec::new();
        let mut ok = true;
        for i in 0..bucket.total {
            match bucket.chunks.get(&i) {
                Some(s) => payload.extend_from_slice(s),
                None => {
                    send_error(
                        &socket,
                        &peer,
                        bucket.stream_id,
                        frame.sequence,
                        500,
                        &format!("internal: missing chunk idx={}", i),
                    );
                    ok = false;
                    break;
                }
            }
        }
        if !ok {
            continue;
        }
        let reassembled = FlowFrame {
            stream_id: bucket.stream_id,
            sequence: frame.sequence,
            flags: bucket.base_flags,
            payload,
        };
        let st = Arc::clone(&station);
        let sk = Arc::clone(&socket);
        std::thread::spawn(move || {
            dispatch(&st, &sk, peer, reassembled);
        });
    }
}

// ─────────────────────────────────────────────────────────────────────
// Knot dim sniffer (mirror fat-station-flow.rs)
// ─────────────────────────────────────────────────────────────────────

fn sniff_dims(path: &str) -> (usize, usize) {
    use std::fs::File;
    use std::io::Read as _;
    let Ok(mut f) = File::open(path) else {
        return (151_936, 3584);
    };
    let mut head = vec![0u8; 4 * 1024 * 1024];
    let n = f.read(&mut head).unwrap_or(0);
    if n < 16 || &head[0..4] != b"KNOT" {
        return (151_936, 3584);
    }
    let mut len_bytes = [0u8; 4];
    len_bytes.copy_from_slice(&head[6..10]);
    let metadata_length = u32::from_le_bytes(len_bytes) as usize;
    if 10 + metadata_length > n {
        return (151_936, 3584);
    }
    let Ok(meta_str) = std::str::from_utf8(&head[10..10 + metadata_length]) else {
        return (151_936, 3584);
    };
    let Ok(json) = serde_json::from_str::<serde_json::Value>(meta_str) else {
        return (151_936, 3584);
    };
    let cfg = json
        .get("config")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let vocab = cfg
        .get("vocab_size")
        .and_then(|v| v.as_u64())
        .unwrap_or(151_936) as usize;
    let hidden = cfg
        .get("hidden_dim")
        .and_then(|v| v.as_u64())
        .unwrap_or(3584) as usize;
    (vocab, hidden)
}

// ─────────────────────────────────────────────────────────────────────
// main
// ─────────────────────────────────────────────────────────────────────

fn main() {
    let cli = match parse_cli() {
        Ok(c) => c,
        Err(e) => {
            eprintln!("ERROR: {}\n", e);
            print_usage();
            std::process::exit(2);
        }
    };

    eprintln!(
        "[fat-station-flow-udp] booting role={} layers=[{},{}) bind={} knot={}",
        cli.role.as_str(),
        cli.layers.0,
        cli.layers.1,
        cli.bind,
        cli.knot
    );
    if let Some((s, e)) = cli.vocab {
        eprintln!("[fat-station-flow-udp] vocab=[{},{})", s, e);
    }

    let t_boot = std::time::Instant::now();
    let pipeline = NativeLlamaPipeline::new(cli.knot.clone(), false, 0.9);
    eprintln!(
        "[fat-station-flow-udp] pipeline ready in {} ms",
        t_boot.elapsed().as_millis()
    );
    let (vocab_size, hidden_dim) = sniff_dims(&cli.knot);
    eprintln!(
        "[fat-station-flow-udp] dims: vocab_size={} hidden_dim={}",
        vocab_size, hidden_dim
    );

    let liquid_cap: usize = std::env::var("GNOSIS_LIQUID_SHARD_BYTES")
        .ok()
        .and_then(|s| s.parse().ok())
        .unwrap_or(1024 * 1024);
    eprintln!(
        "[fat-station-flow-udp] liquid_pool={} bytes (0xF001 / 0xF002)",
        liquid_cap
    );

    let station = Arc::new(Station {
        pipeline: Mutex::new(pipeline),
        liquid_pool: Mutex::new(vec![0u8; liquid_cap]),
        role: cli.role,
        layers: cli.layers,
        vocab: cli.vocab,
        vocab_size,
        hidden_dim,
    });

    let socket = match UdpSocket::bind(&cli.bind) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("ERROR: bind {}: {}", cli.bind, e);
            std::process::exit(3);
        }
    };
    // Bump the kernel recv buffer where possible (best-effort, ignore
    // failures — Linux + macOS both accept SO_RCVBUF via libc::setsockopt
    // but std::net::UdpSocket doesn't expose it portably). The default
    // 256 KiB is enough for any single legal request.
    let actual = socket
        .local_addr()
        .map(|a| a.to_string())
        .unwrap_or_else(|_| cli.bind.clone());
    eprintln!(
        "[fat-station-flow-udp] listening on udp://{} (aeon-flow framing, no length prefix)",
        actual
    );

    let socket = Arc::new(socket);
    dispatcher_loop(station, socket);
}
